if (ctx.containsKey('agent') && ctx.agent != null) {
  if (!ctx.containsKey('host') || ctx.host == null) {
    ctx['host'] = new HashMap();
  }
  Map agent = ctx.agent;
  Map host = ctx.host;
  if (agent.containsKey('id') && (!host.containsKey('id') || host['id'] == null)) {
    host['id'] = agent['id'];
  }
  if (!host.containsKey('name') || host['name'] == null) {
    if (agent.containsKey('name') && agent['name'] != null) {
      host['name'] = agent['name'];
    } else if (agent.containsKey('hostname') && agent['hostname'] != null) {
      host['name'] = agent['hostname'];
    }
  }
}
if (!ctx.containsKey('m2614') || ctx.m2614 == null) {
  ctx['m2614'] = new HashMap();
}
ctx['m2614']['managed'] = true;
ctx['m2614']['hwam_source'] = 'osquery';
